{
  "name": "StaffBreak Manager Pro",
  "description": "Μια εξελιγμένη εφαρμογή διαχείρισης διαλειμμάτων προσωπικού με ανάλυση AI, ιστορικό και παρακολούθηση σε πραγματικό χρόνο.",
  "requestFramePermissions": []
}

export interface Staff {
  id: string;
  name: string;
  role: string;
  isActive: boolean;
}

export interface BreakRecord {
  id: string;
  staffId: string;
  staffName: string;
  startTime: number;
  endTime?: number;
  duration?: number; // in minutes
}

export type ViewType = 'dashboard' | 'staff' | 'history' | 'insights';

export const APP_TITLE = "StaffBreak Manager";

export const ROLE_OPTIONS = [
  "Πωλητής",
  "Ταμίας",
  "Αποθηκάριος",
  "Διευθυντής",
  "Υπάλληλος Γραφείου",
  "Τεχνικός"
];

export const GREEK_MONTHS = [
  "Ιανουαρίου", "Φεβρουαρίου", "Μαρτίου", "Απριλίου", "Μαΐου", "Ιουνίου",
  "Ιουλίου", "Αυγούστου", "Σεπτεμβρίου", "Οκτωβρίου", "Νοεμβρίου", "Δεκεμβρίου"
];

import { GoogleGenAI, Type } from "@google/genai";
import { BreakRecord, Staff } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getBreakInsights = async (breaks: BreakRecord[], staff: Staff[]) => {
  if (breaks.length === 0) return "Δεν υπάρχουν αρκετά δεδομένα για ανάλυση.";

  const prompt = `
    Αναλύστε τα παρακάτω δεδομένα διαλειμμάτων προσωπικού και δώστε μια σύντομη αναφορά στα Ελληνικά.
    Προσωπικό: ${JSON.stringify(staff)}
    Διαλείμματα: ${JSON.stringify(breaks.map(b => ({
      name: b.staffName,
      duration: b.duration || 0,
      time: new Date(b.startTime).toLocaleTimeString('el-GR')
    })))}

    Δώστε:
    1. Σύνοψη της ημέρας.
    2. Εντοπισμό ασυνήθιστων μοτίβων (π.χ. πολύ μεγάλα διαλείμματα).
    3. Προτάσεις για καλύτερο προγραμματισμό.

    Η απάντηση πρέπει να είναι σε μορφή Markdown.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
    });
    return response.text || "Δεν ήταν δυνατή η ανάλυση των δεδομένων.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Σφάλμα κατά την επικοινωνία με την AI.";
  }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import { Staff, BreakRecord, ViewType } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import StaffManager from './components/StaffManager';
import History from './components/History';
import Insights from './components/Insights';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [staff, setStaff] = useState<Staff[]>([]);
  const [breaks, setBreaks] = useState<BreakRecord[]>([]);

  // Load data from localStorage
  useEffect(() => {
    const savedStaff = localStorage.getItem('staff_data');
    const savedBreaks = localStorage.getItem('break_data');
    if (savedStaff) setStaff(JSON.parse(savedStaff));
    if (savedBreaks) setBreaks(JSON.parse(savedBreaks));
  }, []);

  // Sync data to localStorage
  useEffect(() => {
    localStorage.setItem('staff_data', JSON.stringify(staff));
  }, [staff]);

  useEffect(() => {
    localStorage.setItem('break_data', JSON.stringify(breaks));
  }, [breaks]);

  const addStaff = (name: string, role: string) => {
    const newStaff: Staff = {
      id: crypto.randomUUID(),
      name,
      role,
      isActive: false
    };
    setStaff([...staff, newStaff]);
  };

  const removeStaff = (id: string) => {
    setStaff(staff.filter(s => s.id !== id));
    setBreaks(breaks.filter(b => b.staffId !== id));
  };

  const startBreak = (staffId: string) => {
    const member = staff.find(s => s.id === staffId);
    if (!member || member.isActive) return;

    const newBreak: BreakRecord = {
      id: crypto.randomUUID(),
      staffId,
      staffName: member.name,
      startTime: Date.now()
    };

    setStaff(staff.map(s => s.id === staffId ? { ...s, isActive: true } : s));
    setBreaks([newBreak, ...breaks]);
  };

  const endBreak = (staffId: string) => {
    const now = Date.now();
    setStaff(staff.map(s => s.id === staffId ? { ...s, isActive: false } : s));

    setBreaks(breaks.map(b => {
      if (b.staffId === staffId && !b.endTime) {
        const duration = Math.round((now - b.startTime) / 60000); // minutes
        return { ...b, endTime: now, duration };
      }
      return b;
    }));
  };

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard staff={staff} startBreak={startBreak} endBreak={endBreak} />;
      case 'staff':
        return <StaffManager staff={staff} onAdd={addStaff} onRemove={removeStaff} />;
      case 'history':
        return <History breaks={breaks} />;
      case 'insights':
        return <Insights breaks={breaks} staff={staff} />;
      default:
        return <Dashboard staff={staff} startBreak={startBreak} endBreak={endBreak} />;
    }
  };

  return (
    <div className="flex flex-col md:flex-row min-h-screen bg-slate-50">
      <Sidebar currentView={currentView} setView={setCurrentView} />
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        <div className="max-w-6xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

