export default StaffManager;

import React, { useState } from 'react';
import { BreakRecord } from '../types';

interface HistoryProps {
  breaks: BreakRecord[];
}

const History: React.FC<HistoryProps> = ({ breaks }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredBreaks = breaks.filter(b => 
    b.staffName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const formatTime = (ts: number) => {
    return new Date(ts).toLocaleTimeString('el-GR', {
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const formatDate = (ts: number) => {
    return new Date(ts).toLocaleDateString('el-GR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric'
    });
  };

  return (
    <div className="space-y-8">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800">Ιστορικό Διαλειμμάτων</h2>
          <p className="text-slate-500">Προβολή όλων των καταγεγραμμένων διαλειμμάτων.</p>
        </div>
        <div className="relative">
          <input
            type="text"
            placeholder="Αναζήτηση υπαλλήλου..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none w-full md:w-64"
          />
          <span className="absolute left-3 top-2.5 text-slate-400">🔍</span>
        </div>
      </header>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Ημερομηνία</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Υπάλληλος</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Έναρξη</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Λήξη</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider text-right">Διάρκεια</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredBreaks.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-slate-400 italic">
                    Δεν βρέθηκαν εγγραφές.
                  </td>
                </tr>
              ) : (
                filteredBreaks.map(record => (
                  <tr key={record.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 text-slate-600 font-medium">
                      {formatDate(record.startTime)}
                    </td>
                    <td className="px-6 py-4 font-semibold text-slate-900">{record.staffName}</td>
                    <td className="px-6 py-4 text-slate-600">{formatTime(record.startTime)}</td>
                    <td className="px-6 py-4 text-slate-600">
                      {record.endTime ? formatTime(record.endTime) : <span className="text-orange-600 animate-pulse">Σε εξέλιξη...</span>}
                    </td>
                    <td className="px-6 py-4 text-right">
                      {record.duration ? (
                        <span className={`font-bold ${record.duration > 30 ? 'text-red-500' : 'text-slate-700'}`}>
                          {record.duration} λ.
                        </span>
                      ) : '-'}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default History;

import React, { useState, useEffect } from 'react';
import { BreakRecord, Staff } from '../types';
import { getBreakInsights } from '../services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface InsightsProps {
  breaks: BreakRecord[];
  staff: Staff[];
}

const Insights: React.FC<InsightsProps> = ({ breaks, staff }) => {
  const [aiReport, setAiReport] = useState<string>('');
  const [loading, setLoading] = useState(false);

  const fetchInsights = async () => {
    setLoading(true);
    const report = await getBreakInsights(breaks, staff);
    setAiReport(report);
    setLoading(false);
  };

  useEffect(() => {
    if (breaks.length > 0) {
      fetchInsights();
    }
  }, []);

  // Prepare data for the chart: Total break time per employee
  const chartData = staff.map(s => {
    const totalMinutes = breaks
      .filter(b => b.staffId === s.id && b.duration)
      .reduce((acc, curr) => acc + (curr.duration || 0), 0);
    return {
      name: s.name.split(' ')[0], // First name only for display
      minutes: totalMinutes
    };
  }).filter(d => d.minutes > 0);

  return (
    <div className="space-y-8">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold text-slate-800">Ανάλυση AI & Στατιστικά</h2>
          <p className="text-slate-500">Ευφυείς παρατηρήσεις για τη βελτίωση της παραγωγικότητας.</p>
        </div>
        <button
          onClick={fetchInsights}
          disabled={loading || breaks.length === 0}
          className={`px-4 py-2 bg-blue-600 text-white rounded-lg flex items-center gap-2 transition-all ${
            loading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-700 shadow-md'
          }`}
        >
          {loading ? '⌛ Αναλύεται...' : '🔄 Ανανέωση Ανάλυσης'}
        </button>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Statistics Chart */}
        <section className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-semibold mb-6 text-slate-700">Συνολικός Χρόνος Διαλειμμάτων (λεπτά)</h3>
          <div className="h-[300px] w-full">
            {chartData.length === 0 ? (
              <div className="h-full flex items-center justify-center text-slate-400 italic">
                Δεν υπάρχουν αρκετά δεδομένα για γράφημα.
              </div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                  <Tooltip 
                    cursor={{fill: '#f8fafc'}}
                    contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}}
                  />
                  <Bar dataKey="minutes" radius={[4, 4, 0, 0]}>
                    {chartData.map((entry, index) => (
