  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [shift, setShift] = useState(SHIFT_OPTIONS[0]);
  const [schedule, setSchedule] = useState(SCHEDULE_OPTIONS[0]);

  const [staffEntries, setStaffEntries] = useState([
    { name: '', from: '', to: '' },
    { name: '', from: '', to: '' },
    { name: '', from: '', to: '' },
    { name: '', from: '', to: '' },
  ]);

  const handleStaffChange = (index: number, field: 'name' | 'from' | 'to', value: string) => {
    const newEntries = [...staffEntries];
    newEntries[index][field] = value;
    setStaffEntries(newEntries);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const records = staffEntries
      .filter(entry => entry.name.trim() !== '')
      .map(entry => ({
        staffName: entry.name,
        date,
        shift,
        schedule,
        breakFrom: entry.from,
        breakTo: entry.to
