                        <TimeBadge from={record.break30_2_From} to={record.break30_2_To} label="2ο 30'" color="border-blue-300 text-blue-800" />
                        <TimeBadge from={record.break10_1_From} to={record.break10_1_To} label="1ο 10'" color="border-orange-200 text-orange-700" />
                        <TimeBadge from={record.break10_2_From} to={record.break10_2_To} label="2ο 10'" color="border-emerald-200 text-emerald-700" />
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

