                          <input type="time" value={entry.b10_2_t} onChange={(e) => handleStaffChange(index, 'b10_2_t', e.target.value)} className={timeInputClass} />
                        </div>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="p-6 bg-slate-50 border-t border-slate-200 flex flex-col md:flex-row justify-end gap-3">
          <button
            type="button"
            onClick={() => setIsSelectionMode(true)}
            className="w-full md:w-auto px-6 py-4 bg-white text-slate-700 border border-slate-300 rounded-xl font-bold hover:bg-slate-50 transition-all flex items-center justify-center gap-2 group shadow-sm active:scale-95"
          >
            <span>✏️</span>
            Διόρθωση Εγγραφών
          </button>
          <button
            type="submit"
            className={`w-full md:w-auto px-10 py-4 text-white rounded-xl font-bold shadow-lg transition-all flex items-center justify-center gap-3 group active:scale-95 ${
              editingIds.length > 0 ? 'bg-amber-600 hover:bg-amber-700 shadow-amber-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'
            }`}
          >
            <span className="text-xl group-hover:rotate-12 transition-transform">
              {editingIds.length > 0 ? '🆙' : '💾'}
            </span>
            {editingIds.length > 0 ? 'Ενημέρωση Εγγραφών' : 'Οριστική Αποθήκευση'}
          </button>
        </div>
      </form>
    </div>
  );
};

