export type ViewType = 'dashboard' | 'staff' | 'history' | 'insights';

import React, { useState, useMemo } from 'react';
import { SHIFT_OPTIONS, SCHEDULE_OPTIONS } from '../constants';
import { BreakRecord } from '../types';

interface DashboardProps {
  onSave: (entries: Omit<BreakRecord, 'id' | 'createdAt'>[]) => void;
  onUpdate: (entries: BreakRecord[]) => void;
  recentBreaks: BreakRecord[];
}

const Dashboard: React.FC<DashboardProps> = ({ onSave, onUpdate, recentBreaks }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [shift, setShift] = useState(SHIFT_OPTIONS[0]);
  const [schedule, setSchedule] = useState(SCHEDULE_OPTIONS[0]);
  const [supervisorName, setSupervisorName] = useState('');
  const [showExtraBreaks, setShowExtraBreaks] = useState(false);
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [editingIds, setEditingIds] = useState<string[]>([]);

  const initialEntry = { 
    id: '',
    name: '', 
    b30_1_f: '', b30_1_t: '',
    b30_2_f: '', b30_2_t: '',
    b10_1_f: '', b10_1_t: '',
    b10_2_f: '', b10_2_t: ''
  };

  const [staffEntries, setStaffEntries] = useState(Array(4).fill(null).map(() => ({ ...initialEntry })));

  // Group recent breaks by their "save session" (Date, Shift, Schedule, and approximate time)
  const groupedBreaks = useMemo(() => {
    const groups: Record<string, BreakRecord[]> = {};
    // Only show breaks from the last 48 hours for correction
    const limit = Date.now() - (48 * 60 * 60 * 1000);

    recentBreaks
      .filter(b => b.createdAt > limit)
      .forEach(b => {
        // Create a key based on shared properties and a 1-minute window of createdAt
        const timeKey = Math.floor(b.createdAt / 60000);
        const key = `${b.date}-${b.shift}-${b.schedule}-${timeKey}`;
        if (!groups[key]) groups[key] = [];
        groups[key].push(b);
      });
    return Object.values(groups).sort((a, b) => b[0].createdAt - a[0].createdAt);
  }, [recentBreaks]);

  const handleStaffChange = (index: number, field: string, value: string) => {
    const newEntries = [...staffEntries];
    (newEntries[index] as any)[field] = value;
    setStaffEntries(newEntries);
  };

  const selectGroupToEdit = (group: BreakRecord[]) => {
    const first = group[0];
    setDate(first.date);
    setShift(first.shift);
    setSchedule(first.schedule);
    setSupervisorName(first.supervisorName || '');

    const ids: string[] = [];
    const newEntries = Array(4).fill(null).map((_, i) => {
      const record = group[i];
      if (record) {
        ids.push(record.id);
        return {
          id: record.id,
          name: record.staffName,
          b30_1_f: record.break30_1_From, b30_1_t: record.break30_1_To,
          b30_2_f: record.break30_2_From, b30_2_t: record.break30_2_To,
          b10_1_f: record.break10_1_From, b10_1_t: record.break10_1_To,
          b10_2_f: record.break10_2_From, b10_2_t: record.break10_2_To
        };
      }
      return { ...initialEntry };
    });

    setStaffEntries(newEntries);
    setEditingIds(ids);
    setIsSelectionMode(false);
  };

  const cancelEdit = () => {
    setEditingIds([]);
    setSupervisorName('');
    setStaffEntries(Array(4).fill(null).map(() => ({ ...initialEntry })));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const filledEntries = staffEntries.filter(entry => entry.name.trim() !== '');

    if (filledEntries.length === 0) {
      alert("Παρακαλώ εισάγετε τουλάχιστον ένα όνομα υπαλλήλου.");
      return;
    }

    if (editingIds.length > 0) {
      // Update logic
      const updatedRecords: BreakRecord[] = filledEntries.map(entry => ({
        id: entry.id || crypto.randomUUID(),
        staffName: entry.name,
        supervisorName,
        date,
        shift,
        schedule,
        break30_1_From: entry.b30_1_f,
        break30_1_To: entry.b30_1_t,
        break30_2_From: entry.b30_2_f,
        break30_2_To: entry.b30_2_t,
        break10_1_From: entry.b10_1_f,
        break10_1_To: entry.b10_1_t,
        break10_2_From: entry.b10_2_f,
        break10_2_To: entry.b10_2_t,
        createdAt: Date.now()
      }));
      onUpdate(updatedRecords);
    } else {
      // Normal save
      const records = filledEntries.map(entry => ({
        staffName: entry.name,
        supervisorName,
        date,
        shift,
        schedule,
        break30_1_From: entry.b30_1_f,
        break30_1_To: entry.b30_1_t,
        break30_2_From: entry.b30_2_f,
        break30_2_To: entry.b30_2_t,
        break10_1_From: entry.b10_1_f,
        break10_1_To: entry.b10_1_t,
        break10_2_From: entry.b10_2_f,
        break10_2_To: entry.b10_2_t,
      }));
      onSave(records);
    }

    setStaffEntries(Array(4).fill(null).map(() => ({ ...initialEntry })));
    setSupervisorName('');
    setEditingIds([]);
  };

  const timeInputClass = "w-full bg-white px-1 py-2 rounded-lg border border-slate-300 text-base font-medium font-mono focus:ring-2 focus:ring-blue-500 outline-none shadow-sm transition-all text-center text-slate-800";

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto pb-20">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800 tracking-tight">
            {editingIds.length > 0 ? 'Διόρθωση Εγγραφής' : 'Νέα Καταχώριση Βάρδιας'}
          </h2>
          <p className="text-slate-500 text-sm">
            {editingIds.length > 0 ? 'Τροποποιήστε τα στοιχεία της επιλεγμένης βάρδιας.' : 'Καταχωρίστε τα διαλείμματα του προσωπικού για σήμερα.'}
          </p>
        </div>
        <div className="flex gap-2">
          <button
            type="button"
            onClick={() => setShowExtraBreaks(!showExtraBreaks)}
            className={`px-4 py-2 rounded-xl font-bold text-sm transition-all flex items-center gap-2 border shadow-sm ${
              showExtraBreaks 
              ? 'bg-slate-800 text-white border-slate-800 hover:bg-slate-700' 
              : 'bg-white text-blue-600 border-blue-200 hover:bg-blue-50'
            }`}
          >
            <span>{showExtraBreaks ? '🏠' : '➕'}</span>
            {showExtraBreaks ? 'Επιστροφή στο 1st Διάλειμμα' : 'Επιπλέον Διάλειμμα'}
          </button>
        </div>
      </header>

      {editingIds.length > 0 && (
        <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl flex items-center justify-between animate-in slide-in-from-top-2">
          <div className="flex items-center gap-3">
            <span className="text-2xl">⚠️</span>
            <div>
              <p className="text-amber-800 font-bold text-sm uppercase tracking-wider">Λειτουργία Διόρθωσης</p>
              <p className="text-amber-600 text-xs">Επεξεργάζεστε μια υπάρχουσα καταχώριση. Πατήστε "Ενημέρωση" για να σωθούν οι αλλαγές.</p>
            </div>
          </div>
          <button 
            onClick={cancelEdit}
            className="px-3 py-1 bg-white border border-amber-300 text-amber-700 rounded-lg text-xs font-bold hover:bg-amber-100 transition-colors"
          >
            Ακύρωση & Νέα Καταχώριση
          </button>
        </div>
      )}

      <form onSubmit={handleSubmit} className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden relative">
        {isSelectionMode && (
          <div className="absolute inset-0 z-50 bg-slate-900/40 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
              <div className="p-4 border-b border-slate-100 flex items-center justify-between bg-slate-50">
                <h4 className="font-bold text-slate-800 uppercase tracking-tight text-sm">Επιλογή Καταχώρισης για Διόρθωση</h4>
                <button onClick={() => setIsSelectionMode(false)} className="text-slate-400 hover:text-slate-600">✕</button>
              </div>
              <div className="max-h-[60vh] overflow-y-auto p-4 space-y-3">
                {groupedBreaks.length === 0 ? (
                  <p className="text-center py-10 text-slate-400 italic">Δεν βρέθηκαν πρόσφατες εγγραφές.</p>
                ) : (
                  groupedBreaks.map((group, idx) => (
                    <button
                      key={idx}
                      type="button"
                      onClick={() => selectGroupToEdit(group)}
                      className="w-full text-left p-4 rounded-xl border border-slate-200 hover:border-blue-500 hover:bg-blue-50 transition-all flex items-center justify-between group"
                    >
                      <div>
                        <div className="flex items-center gap-2 mb-1">
                          <span className="text-[10px] font-black bg-slate-200 px-1.5 py-0.5 rounded uppercase">{group[0].shift}</span>
                          <span className="text-[10px] font-black bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded uppercase">{group[0].schedule}</span>
                          <span className="text-xs font-bold text-slate-600">{new Date(group[0].date).toLocaleDateString('el-GR')}</span>
                        </div>
                        <p className="text-sm font-medium text-slate-800">
                          {group.map(b => b.staffName).join(', ')}
                        </p>
                      </div>
                      <span className="text-blue-500 opacity-0 group-hover:opacity-100 transition-opacity">✏️</span>
                    </button>
                  ))
                )}
              </div>
            </div>
          </div>
        )}

        <div className="p-4 md:p-8 space-y-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Ημερομηνία</label>
              <input
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                required
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Βάρδια</label>
              <select
                value={shift}
                onChange={(e) => setShift(e.target.value)}
                className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
              >
                {SHIFT_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Ωράριο</label>
              <select
