              />
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="text-lg font-semibold text-slate-800 pb-2 border-b border-slate-100 flex items-center gap-2">
              <span>📋</span> Λεπτομέρειες Διαλειμμάτων
            </h3>

            <div className="hidden lg:grid grid-cols-12 gap-2 px-2 text-[10px] font-bold text-slate-400 uppercase tracking-wider items-end">
              <div className="col-span-1 text-center pb-2">#</div>
              {!showExtraBreaks ? (
                <>
                  <div className="col-span-4 pb-2">Ονοματεπώνυμο</div>
                  <div className="col-span-4">
                    <div className="text-center text-blue-600 bg-blue-50 py-1 rounded-t-lg border-x border-t border-blue-100 mb-1 font-black">1st 30 ΛΕΠΤΟ</div>
                    <div className="grid grid-cols-2 gap-1 text-[8px] text-center">
                      <span>ΑΠΟ</span><span>ΕΩΣ</span>
                    </div>
                  </div>
                  <div className="col-span-3"></div>
                </>
              ) : (
                <>
                  <div className="col-span-2 pb-2">Ονοματεπώνυμο</div>
                  <div className="col-span-3 animate-in fade-in">
                    <div className="text-center text-blue-700 bg-blue-100/50 py-1 rounded-t-lg border-x border-t border-blue-200 mb-1 font-black">2nd 30 ΛΕΠΤΟ</div>
                    <div className="grid grid-cols-2 gap-1 text-[8px] text-center">
                      <span>ΑΠΟ</span><span>ΕΩΣ</span>
                    </div>
                  </div>
                  <div className="col-span-3 animate-in fade-in">
                    <div className="text-center text-orange-600 bg-orange-50 py-1 rounded-t-lg border-x border-t border-orange-100 mb-1 font-black">1st 10 ΛΕΠΤΟ</div>
                    <div className="grid grid-cols-2 gap-1 text-[8px] text-center">
                      <span>ΑΠΟ</span><span>ΕΩΣ</span>
                    </div>
                  </div>
                  <div className="col-span-3 animate-in fade-in">
                    <div className="text-center text-emerald-600 bg-emerald-50 py-1 rounded-t-lg border-x border-t border-emerald-100 mb-1 font-black">2nd 10 ΛΕΠΤΟ</div>
                    <div className="grid grid-cols-2 gap-1 text-[8px] text-center">
                      <span>ΑΠΟ</span><span>ΕΩΣ</span>
                    </div>
                  </div>
                </>
              )}
            </div>

            <div className="space-y-4 lg:space-y-2">
              {staffEntries.map((entry, index) => (
                <div 
                  key={index} 
                  className="grid grid-cols-1 lg:grid-cols-12 gap-3 lg:gap-2 items-center p-4 lg:p-2 bg-white lg:bg-slate-50 rounded-2xl lg:rounded-xl border border-slate-200 lg:border-slate-100 transition-all hover:bg-white hover:shadow-lg group"
                >
                  <div className={`flex items-center gap-3 col-span-1 ${showExtraBreaks ? 'lg:col-span-3' : 'lg:col-span-5'}`}>
                    <span className="w-6 h-6 shrink-0 rounded-full bg-slate-200 text-slate-600 flex items-center justify-center font-bold text-[10px] group-hover:bg-blue-600 group-hover:text-white transition-colors">
                      {index + 1}
