import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { BreakRecord, Staff } from "../types";

export const getBreakInsights = async (breaks: BreakRecord[], staff: Staff[]) => {
  if (breaks.length === 0) return "Δεν υπάρχουν αρκετά δεδομένα για ανάλυση.";

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Αναλύστε τα παρακάτω δεδομένα διαλειμμάτων προσωπικού και δώστε μια σύντομη αναφορά στα Ελληνικά.
    Προσωπικό: ${JSON.stringify(staff)}
    Διαλείμματα: ${JSON.stringify(breaks.map(b => ({
      name: b.staffName,
      supervisor: b.supervisorName,
      date: b.date,
      b30_1: `${b.break30_1_From}-${b.break30_1_To}`,
      b30_2: `${b.break30_2_From}-${b.break30_2_To}`,
      b10_1: `${b.break10_1_From}-${b.break10_1_To}`,
      b10_2: `${b.break10_2_From}-${b.break10_2_To}`,
      shift: b.shift,
      schedule: b.schedule
    })))}

    Δώστε:
    1. Σύνοψη της ημέρας και των βαρδιών.
    2. Έλεγχο αν τηρήθηκαν τα διαστήματα (30λεπτα και 10λεπτα).
    3. Εντοπισμό "αιχμών" όπου πολλά άτομα λείπουν ταυτόχρονα.
    4. Προτάσεις για καλύτερη κατανομή των διαλειμμάτων.

    Η απάντηση πρέπει να είναι σε μορφή Markdown.
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
    });
    return response.text || "Δεν ήταν δυνατή η ανάλυση των δεδομένων.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Σφάλμα κατά την επικοινωνία με την AI.";
  }
};

