import React, { useState, useEffect } from 'react';
import { Staff, BreakRecord, ViewType } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import StaffManager from './components/StaffManager';
import History from './components/History';
import Insights from './components/Insights';

const API_BASE = 'http://localhost:3001/api';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [staff, setStaff] = useState<Staff[]>([]);
  const [breaks, setBreaks] = useState<BreakRecord[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [staffRes, breaksRes] = await Promise.all([
        fetch(`${API_BASE}/staff`),
        fetch(`${API_BASE}/breaks`)
      ]);
      const staffData = await staffRes.json();
      const breaksData = await breaksRes.json();
      setStaff(staffData);
      setBreaks(breaksData);
    } catch (err) {
      console.error("Failed to fetch data:", err);
    } finally {
      setLoading(false);
    }
  };

  const addStaff = async (name: string, role: string) => {
    const newStaffMember: Staff = {
      id: crypto.randomUUID(),
      name,
      role,
      isActive: false
    };
    try {
      const res = await fetch(`${API_BASE}/staff`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newStaffMember)
      });
      const saved = await res.json();
      setStaff([...staff, saved]);
    } catch (err) {
      console.error("Failed to add staff:", err);
    }
  };

  const removeStaff = async (id: string) => {
    try {
      await fetch(`${API_BASE}/staff/${id}`, { method: 'DELETE' });
      setStaff(staff.filter(s => s.id !== id));
    } catch (err) {
      console.error("Failed to remove staff:", err);
    }
  };

  const saveShiftEntry = async (entry: Omit<BreakRecord, 'id' | 'createdAt'>[]) => {
    const newRecords: BreakRecord[] = entry.map(e => ({
      ...e,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    }));

    try {
      const res = await fetch(`${API_BASE}/breaks`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newRecords)
      });
      const saved = await res.json();
      setBreaks([...saved, ...breaks]);
      setCurrentView('history');
    } catch (err) {
      console.error("Failed to save breaks:", err);
    }
  };

  const updateShiftEntry = async (updatedEntries: BreakRecord[]) => {
    try {
      await fetch(`${API_BASE}/breaks`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(updatedEntries)
      });

      const updatedIds = updatedEntries.map(e => e.id);
      const filteredOldBreaks = breaks.filter(b => !updatedIds.includes(b.id));
      setBreaks([...updatedEntries, ...filteredOldBreaks]);
      setCurrentView('history');
    } catch (err) {
      console.error("Failed to update breaks:", err);
    }
  };

  const renderContent = () => {
    if (loading) return (
      <div className="flex items-center justify-center h-[60vh]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );

    switch (currentView) {
      case 'dashboard':
        return <Dashboard onSave={saveShiftEntry} onUpdate={updateShiftEntry} recentBreaks={breaks} />;
      case 'staff':
        return <StaffManager staff={staff} onAdd={addStaff} onRemove={removeStaff} />;
      case 'history':
        return <History breaks={breaks} />;
      case 'insights':
        return <Insights breaks={breaks} staff={staff} />;
      default:
        return <Dashboard onSave={saveShiftEntry} onUpdate={updateShiftEntry} recentBreaks={breaks} />;
    }
  };

  return (
    <div className="flex flex-col md:flex-row min-h-screen bg-slate-50">
      <Sidebar currentView={currentView} setView={setCurrentView} />
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

